'use strict';

var $TypeError = require('es-errors/type');

var CompletionRecord = require('./CompletionRecord');
var IteratorClose = require('./IteratorClose');



module.exports = function IfAbruptCloseIterator(value, iteratorRecord) {
	if (!(value instanceof CompletionRecord)) {
		throw new $TypeError('Assertion failed: `value` must be a Completion Record'); 
	}
	if (value.type() !== 'normal') {
		return IteratorClose(iteratorRecord, value); 
	}

	return value['!'](); 
};
